-- ============================================================================
-- source: core/09_views/001_v_obj_proxy_events.sql
-- ============================================================================
-- object: v_obj_proxy_events
-- folder: views
-- depends_on: proxy_events, obj_wireguard_identity, obj_network_endpoint, obj_traffic_metrics
-- source: sql/oracle.sql lines 898-917

CREATE OR REPLACE VIEW V_OBJ_PROXY_EVENTS AS
SELECT
    ID,
    BATCH_ID,
    EVENT_TIME,
    EVENT_TIMESTAMP_UTC,
    EVENT_TYPE,
    HOST,
    obj_wireguard_identity(WG_PUBKEY, DEVICE_ID, NULL, IDENTITY_SOURCE) AS client_identity,
    obj_network_endpoint(NULL, NULL, HOST) AS destination,
    obj_traffic_metrics(BYTES_UP, BYTES_DOWN, DURATION_MS) AS traffic,
    STATUS_CODE,
    BLOCKED,
    OBFUSCATION_PROFILE,
    CORRELATION_ID,
    PARENT_EVENT_ID,
    EVENT_SEQUENCE,
    REASON,
    RAW_JSON
FROM PROXY_EVENTS;

-- ============================================================================
-- source: core/09_views/002_vw_wireless_active_threats.sql
-- ============================================================================
-- object: vw_wireless_active_threats
-- folder: views
-- depends_on: wireless_alerts
-- source: sql/oracle.sql lines 919-932

CREATE OR REPLACE VIEW VW_WIRELESS_ACTIVE_THREATS AS
SELECT ALERT_TYPE AS THREAT_TYPE,
       CASE ALERT_TYPE WHEN 'bandwidth_threshold' THEN 'CRITICAL' WHEN 'rogue_ap' THEN 'HIGH' WHEN 'deauth_flood' THEN 'HIGH' ELSE 'MEDIUM' END AS SEVERITY,
       DETECTED_AT AS EVENT_AT,
       SENSOR_ID,
       LOCATION_ID,
       PRIMARY_MAC,
       SSID,
       BYTES,
       ALERT_PK,
       ACKNOWLEDGED,
       CASE ALERT_TYPE WHEN 'bandwidth_threshold' THEN 1 WHEN 'rogue_ap' THEN 2 WHEN 'deauth_flood' THEN 2 ELSE 3 END AS SORT_PRIORITY
FROM WIRELESS_ALERTS
WHERE ACKNOWLEDGED = 0;

-- ============================================================================
-- source: core/09_views/003_vw_wireless_bw_daily_summary.sql
-- ============================================================================
-- object: vw_wireless_bw_daily_summary
-- folder: views
-- depends_on: wireless_bandwidth_windows
-- source: sql/oracle.sql lines 934-951

CREATE OR REPLACE VIEW VW_WIRELESS_BW_DAILY_SUMMARY AS
SELECT TRUNC(CAST(WINDOW_START AS DATE)) AS TRAFFIC_DATE,
       SENSOR_ID,
       LOCATION_ID,
       SOURCE_MAC,
       DESTINATION_BSSID,
       SSID,
       EXTERNAL_BSSID,
       SUM(BYTES) AS TOTAL_BYTES,
       SUM(FRAME_COUNT) AS TOTAL_FRAMES,
       SUM(RETRY_COUNT) AS TOTAL_RETRIES,
       MAX(STRONGEST_SIGNAL_DBM) AS MAX_SIGNAL_DBM,
       MIN(STRONGEST_SIGNAL_DBM) AS MIN_SIGNAL_DBM,
       COUNT(*) AS WINDOW_COUNT,
       SUM(CASE WHEN THRESHOLD_EXCEEDED = 1 THEN 1 ELSE 0 END) AS THRESHOLD_EXCEEDED_COUNT,
       AVG(WALL_CLOCK_DELTA_MS) AS AVG_SENSOR_LAG_MS
FROM WIRELESS_BANDWIDTH_WINDOWS
GROUP BY TRUNC(CAST(WINDOW_START AS DATE)), SENSOR_ID, LOCATION_ID, SOURCE_MAC, DESTINATION_BSSID, SSID, EXTERNAL_BSSID;

-- ============================================================================
-- source: core/09_views/004_vw_wireless_current_clients.sql
-- ============================================================================
-- object: vw_wireless_current_clients
-- folder: views
-- depends_on: wireless_client_inventory
-- source: sql/oracle.sql lines 953-960

CREATE OR REPLACE VIEW VW_WIRELESS_CURRENT_CLIENTS AS
SELECT inv.*
FROM WIRELESS_CLIENT_INVENTORY inv
JOIN (
    SELECT SENSOR_ID, MAX(SNAPSHOT_AT) AS LATEST_SNAP
    FROM WIRELESS_CLIENT_INVENTORY
    GROUP BY SENSOR_ID
) latest ON inv.SENSOR_ID = latest.SENSOR_ID AND inv.SNAPSHOT_AT = latest.LATEST_SNAP;

-- ============================================================================
-- source: core/10_scheduler/001_wireless_gather_stats_nightly.sql
-- ============================================================================
-- object: wireless_gather_stats_nightly
-- folder: scheduler
-- depends_on: wireless_audit_frames, wireless_bandwidth_windows, wireless_client_inventory
-- source: sql/oracle.sql lines 962-978

BEGIN
    DBMS_SCHEDULER.CREATE_JOB (
        job_name => 'WIRELESS_GATHER_STATS_NIGHTLY',
        job_type => 'PLSQL_BLOCK',
        job_action => 'BEGIN DBMS_STATS.GATHER_TABLE_STATS(USER, ''WIRELESS_AUDIT_FRAMES'', granularity=>''AUTO'', options=>''GATHER AUTO'', degree=>4); DBMS_STATS.GATHER_TABLE_STATS(USER, ''WIRELESS_BANDWIDTH_WINDOWS'', granularity=>''AUTO'', options=>''GATHER AUTO'', degree=>4); DBMS_STATS.GATHER_TABLE_STATS(USER, ''WIRELESS_CLIENT_INVENTORY'', granularity=>''AUTO'', options=>''GATHER AUTO'', degree=>2); END;',
        start_date => SYSTIMESTAMP,
        repeat_interval => 'FREQ=DAILY;BYHOUR=3;BYMINUTE=0',
        enabled => TRUE,
        comments => 'Nightly CBO stats refresh for wireless tables'
    );
EXCEPTION
    WHEN OTHERS THEN
        IF SQLCODE != -27477 THEN
            RAISE;
        END IF;
END;
/

-- ============================================================================
-- source: core/11_security/001_audit_retention_tampering.sql
-- ============================================================================
-- object: audit_retention_tampering
-- folder: security
-- depends_on: proxy_data_retention_policies
-- source: sql/oracle.sql lines 853-867

BEGIN
    DBMS_FGA.ADD_POLICY(
        object_schema   => USER,
        object_name     => 'PROXY_DATA_RETENTION_POLICIES',
        policy_name     => 'AUDIT_RETENTION_TAMPERING',
        audit_condition => 'ENABLED = 0 OR RETAIN_DAYS < 30',
        statement_types => 'INSERT,UPDATE'
    );
    DBMS_FGA.ADD_POLICY(
        object_schema   => USER,
        object_name     => 'PROXY_DATA_RETENTION_POLICIES',
        policy_name     => 'AUDIT_RETENTION_DELETE',
        audit_condition => NULL,
        statement_types => 'DELETE'
    );
EXCEPTION
    WHEN OTHERS THEN
        IF SQLCODE != -28101 THEN
            RAISE;
        END IF;
END;
/

-- ============================================================================
-- source: core/11_security/002_vpd_append_only.sql
-- ============================================================================
-- object: vpd_append_only
-- folder: security
-- depends_on: proxy_append_only_policy, proxy_events, proxy_payload_audit, proxy_blocklist_audit, proxy_db_query_log, wireless_audit_frames, wireless_alerts_ledger
-- source: sql/oracle.sql lines 869-896

DECLARE
    PROCEDURE add_append_only_policy(p_table_name IN VARCHAR2) AS
    BEGIN
        DBMS_RLS.ADD_POLICY(
            object_schema   => USER,
            object_name     => p_table_name,
            policy_name     => 'VPD_APPEND_ONLY',
            function_schema => USER,
            policy_function => 'PROXY_APPEND_ONLY_POLICY',
            statement_types => 'SELECT,UPDATE,DELETE',
            update_check    => FALSE,
            enable          => TRUE
        );
    EXCEPTION
        WHEN OTHERS THEN
            IF SQLCODE != -28101 THEN
                RAISE;
            END IF;
    END;
BEGIN
    add_append_only_policy('PROXY_EVENTS');
    add_append_only_policy('PROXY_PAYLOAD_AUDIT');
    add_append_only_policy('PROXY_BLOCKLIST_AUDIT');
    add_append_only_policy('PROXY_DB_QUERY_LOG');
    add_append_only_policy('WIRELESS_AUDIT_FRAMES');
    add_append_only_policy('WIRELESS_ALERTS_LEDGER');
END;
/

